@* Displays a single task card with move-left/move-right buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="text-muted small">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeftClicked">← Move Left</button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRightClicked">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task OnMoveLeftClicked() => await OnMoveLeft.InvokeAsync();
    private async Task OnMoveRightClicked() => await OnMoveRight.InvokeAsync();
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@saving">
                @(saving ? "Saving…" : "Save")
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="Cancel" disabled="@saving">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(error))
        {
            <div class="text-danger small mt-1">@error</div>
        }
    </div>
</div>

@code {
    [Parameter] public EventCallback OnCancel { get; set; }
    [Parameter] public EventCallback<TaskItem> OnSave { get; set; }
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = default!;

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;
    private string? error;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            error = "Title is required.";
            return;
        }

        saving = true;
        error = null;
        try
        {
            var created = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
            await OnSave.InvokeAsync(created);
        }
        catch (Exception ex)
        {
            error = $"Failed to save: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@* Search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title…"
           @bind="SearchText"
           @bind:event="oninput"
           @bind:after="NotifyChanged" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task NotifyChanged() => await SearchTextChanged.InvokeAsync(SearchText);
}

@* A single Kanban column displaying its tasks and an add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="@(ColumnIndex > 0)"
                          CanMoveRight="@(ColumnIndex < 2)"
                          OnMoveLeft="@(() => MoveTask(task, -1))"
                          OnMoveRight="@(() => MoveTask(task, 1))" />
            }

            @if (showForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             OnSave="HandleTaskCreated"
                             OnCancel="@(() => showForm = false)" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="@(() => showForm = true)" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public int ColumnIndex { get; set; }
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = default!;
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task MoveTask(TaskItem task, int direction)
    {
        var newIndex = ColumnIndex + direction;
        if (newIndex < 0 || newIndex > 2) return;
        await OnMoveTask.InvokeAsync((task.Id, Statuses[newIndex]));
    }

    private async Task HandleTaskCreated(TaskItem created)
    {
        showForm = false;
        await OnTaskCreated.InvokeAsync(created);
    }
}

@page "/board"
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        @for (var i = 0; i < Statuses.Length; i++)
        {
            var index = i;
            var status = Statuses[index];
            var columnTasks = FilteredTasks.Where(t => t.Status == status).ToList();

            <BoardColumn ColumnName="@status"
                         ColumnIndex="index"
                         Tasks="columnTasks"
                         OnMoveTask="HandleMoveTask"
                         OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    private IEnumerable<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchText)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync() => await LoadTasks();

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var task = allTasks.First(t => t.Id == move.TaskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = move.NewStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskCreated(TaskItem created)
    {
        allTasks.Add(created);
    }
}

