@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        @for (var i = 0; i < Statuses.Length; i++)
        {
            var index = i;
            var status = Statuses[index];
            var columnTasks = FilteredTasks.Where(t => t.Status == status).ToList();

            <BoardColumn ColumnName="@status"
                         ColumnIndex="index"
                         Tasks="columnTasks"
                         OnMoveTask="HandleMoveTask"
                         OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    private IEnumerable<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchText)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync() => await LoadTasks();

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var task = allTasks.First(t => t.Id == move.TaskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = move.NewStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskCreated(TaskItem created)
    {
        allTasks.Add(created);
    }
}
"}

