@* Search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title…"
           @bind="SearchText"
           @bind:event="oninput"
           @bind:after="NotifyChanged" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task NotifyChanged() => await SearchTextChanged.InvokeAsync(SearchText);
}

@* A single Kanban column displaying its tasks and an add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="@(ColumnIndex > 0)"
                          CanMoveRight="@(ColumnIndex < 2)"
                          OnMoveLeft="@(() => MoveTask(task, -1))"
                          OnMoveRight="@(() => MoveTask(task, 1))" />
            }

            @if (showForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             OnSave="HandleTaskCreated"
                             OnCancel="@(() => showForm = false)" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="@(() => showForm = true)" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public int ColumnIndex { get; set; }
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = default!;
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task MoveTask(TaskItem task, int direction)
    {
        var newIndex = ColumnIndex + direction;
        if (newIndex < 0 || newIndex > 2) return;
        await OnMoveTask.InvokeAsync((task.Id, Statuses[newIndex]));
    }

    private async Task HandleTaskCreated(TaskItem created)
    {
        showForm = false;
        await OnTaskCreated.InvokeAsync(created);
    }
}

